import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../Navbar";

function AdminDashboard() {
  // Dummy data
  
  //  Filter

  return (
    <div className="min-h-screen bg-gray-100">

     <Navbar/>
      <div className="p-6">

        {/*  Stats */}
        <div className="grid grid-cols-3 gap-4 mb-6">
          <div className="bg-white p-4 rounded shadow">Users: {totalUsers}</div>
          <div className="bg-white p-4 rounded shadow">Stores: {totalStores}</div>
          <div className="bg-white p-4 rounded shadow">Ratings: {totalRatings}</div>
        </div>

        {/*  Add User */}
        {/* Search */}

        {/*  Users Table */}
        

        {/* Stores Table */}
        <div className="bg-white p-4 rounded shadow">
          <h2 className="font-semibold mb-3">Stores</h2>

          <table className="w-full text-center">
            <thead className="bg-indigo-600 text-white">
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Address</th>
                <th>Rating</th>
              </tr>
            </thead>

            <tbody>
              {stores.map((s) => (
                <tr key={s.id} className="border-b">
                  <td>{s.name}</td>
                  <td>{s.email}</td>
                  <td>{s.address}</td>
                  <td>{s.rating}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

      </div>
    </div>
  );
}

export default AdminDashboard;
